204вҶ’std::string BridgeServer::handle_subscribe(const std::string& client_id, const nlohmann::json& request) {
205вҶ’  if (!session_manager_->session_exists(client_id)) {
206вҶ’    session_manager_->create_session(client_id);
207вҶ’    spdlog::info("Created new session for client '{}'", client_id);
208вҶ’  }
209вҶ’
210вҶ’  session_manager_->update_heartbeat(client_id);
211вҶ’
212вҶ’  if (!request.contains("topics")) {
213вҶ’    return create_error_response("INVALID_REQUEST", "Missing 'topics' field", request);
214вҶ’  }
215вҶ’
216вҶ’  if (!request["topics"].is_array()) {
217вҶ’    return create_error_response("INVALID_REQUEST", "'topics' must be an array", request);
218вҶ’  }
219вҶ’
220вҶ’  auto current_subs = session_manager_->get_subscriptions(client_id);
221вҶ’
222вҶ’  // Parse requested topics вҖ” supports mixed array of strings and objects:
223вҶ’  //   ["topic1", {"name": "topic2", "max_rate_hz": 10.0}]
224вҶ’  std::unordered_map<std::string, double> requested_topics;
225вҶ’  for (const auto& topic : request["topics"]) {
226вҶ’    if (topic.is_string()) {
227вҶ’      requested_topics[topic.get<std::string>()] = 0.0;
228вҶ’    } else if (topic.is_object() && topic.contains("name") && topic["name"].is_string()) {
229вҶ’      double rate_hz = 0.0;
230вҶ’      if (topic.contains("max_rate_hz") && topic["max_rate_hz"].is_number()) {
231вҶ’        rate_hz = topic["max_rate_hz"].get<double>();
232вҶ’        if (rate_hz < 0.0) {
233вҶ’          rate_hz = 0.0;
234вҶ’        }
235вҶ’      }
236вҶ’      requested_topics[topic["name"].get<std::string>()] = rate_hz;
237вҶ’    }
238вҶ’  }
239вҶ’
240вҶ’  // Determine which topics to add (additive model вҖ” subscribe only adds, never removes)
241вҶ’  std::vector<std::string> topics_to_add;
242вҶ’  for (const auto& [topic, rate] : requested_topics) {
243вҶ’    if (current_subs.find(topic) == current_subs.end()) {
244вҶ’      topics_to_add.push_back(topic);
245вҶ’    }
246вҶ’  }
247вҶ’
248вҶ’  // Build topic name вҶ’ type lookup from topic source
249вҶ’  auto available_topics = topic_source_->get_topics();
250вҶ’  std::unordered_map<std::string, std::string> topic_types;
251вҶ’  for (const auto& topic : available_topics) {
252вҶ’    topic_types[topic.name] = topic.type;
253вҶ’  }
254вҶ’
255вҶ’  // Subscribe to new topics вҖ” track successes and failures
256вҶ’  json schemas = json::object();
257вҶ’  json failures = json::array();
258вҶ’  std::unordered_set<std::string> successfully_subscribed;
259вҶ’
260вҶ’  for (const auto& topic_name : topics_to_add) {
261вҶ’    if (topic_types.find(topic_name) == topic_types.end()) {
262вҶ’      spdlog::warn("Client '{}' requested non-existent topic '{}'", client_id, topic_name);
263вҶ’      json failure;
264вҶ’      failure["topic"] = topic_name;
265вҶ’      failure["reason"] = "Topic does not exist";
266вҶ’      failures.push_back(failure);
267вҶ’      continue;
268вҶ’    }
269вҶ’
270вҶ’    std::string topic_type = topic_types[topic_name];
271вҶ’
272вҶ’    // Get schema BEFORE subscribing to avoid corrupting the reference count
