  mock_->push_request("client_additive_1", sub1.dump());
  server_->process_requests();
  mock_->pop_reply("client_additive_1");

  // Subscribe to topic_b (should NOT remove topic_a in the new additive model)
  json sub2;
  sub2["command"] = "subscribe";
