  std::shared_ptr<MockMiddleware> mock_;
  std::shared_ptr<MockTopicSource> mock_topic_source_;
  std::shared_ptr<MockSubscriptionManager> mock_sub_manager_;
  std::unique_ptr<BridgeServer> server_;
};

