64вҶ’void MessageBuffer::cleanup_old_messages() {
65вҶ’  uint64_t current_time = get_current_time_ns();
66вҶ’
67вҶ’  for (auto& [topic, buffer] : topic_buffers_) {
68вҶ’    while (!buffer.empty()) {
69вҶ’      const auto& oldest_msg = buffer.front();
70вҶ’      if (current_time - oldest_msg.received_at_ns > max_message_age_ns_) {
71вҶ’        buffer.pop_front();
72вҶ’      } else {
73вҶ’        break;
74вҶ’      }
75вҶ’    }
76вҶ’  }
77вҶ’
78вҶ’  for (auto it = topic_buffers_.begin(); it != topic_buffers_.end();) {
79вҶ’    if (it->second.empty()) {
80вҶ’      it = topic_buffers_.erase(it);
81вҶ’    } else {
82вҶ’      ++it;
83вҶ’    }
84вҶ’  }
