144вҶ’    // callback captures `this`, so it must not fire after the WebSocketMiddleware
145вҶ’    // instance is destroyed (which can happen if the stop thread is detached on timeout).
146вҶ’    server_to_stop->setOnClientMessageCallback(
147вҶ’        [](std::shared_ptr<ix::ConnectionState>, ix::WebSocket&, const ix::WebSocketMessagePtr&) {});
148вҶ’
149вҶ’    // Initiate graceful close on all connected clients before calling stop().
150вҶ’    spdlog::debug("[shutdown] Pre-closing {} WebSocket client(s)...", server_to_stop->getClients().size());
151вҶ’    for (const auto& client : server_to_stop->getClients()) {
152вҶ’      client->close();
153вҶ’    }
154вҶ’
155вҶ’    // Run stop() on a dedicated thread with a timeout.
156вҶ’    spdlog::debug("[shutdown] Starting server stop thread...");
157вҶ’    auto done = std::make_shared<std::atomic<bool>>(false);
158вҶ’    std::thread stop_thread([server_to_stop, done]() {
159вҶ’      server_to_stop->stop();
160вҶ’      done->store(true);
161вҶ’    });
162вҶ’
163вҶ’    auto start = std::chrono::steady_clock::now();
164вҶ’    auto deadline = start + std::chrono::seconds(kShutdownTimeoutSeconds);
165вҶ’    while (!done->load() && std::chrono::steady_clock::now() < deadline) {
166вҶ’      std::this_thread::sleep_for(std::chrono::milliseconds(50));
167вҶ’    }
168вҶ’    auto elapsed_ms =
169вҶ’        std::chrono::duration_cast<std::chrono::milliseconds>(std::chrono::steady_clock::now() - start).count();
170вҶ’
171вҶ’    if (done->load()) {
172вҶ’      stop_thread.join();
173вҶ’      spdlog::debug("[shutdown] Server stop completed (took {}ms)", elapsed_ms);
174вҶ’    } else {
