181вҶ’          kShutdownTimeoutSeconds, elapsed_ms);
182вҶ’      stop_thread.detach();
183вҶ’    }
184вҶ’  }
185вҶ’
186вҶ’  {
187вҶ’    std::lock_guard<std::mutex> clients_lock(clients_mutex_);
188вҶ’    clients_.clear();
189вҶ’  }
190вҶ’
191вҶ’  {
192вҶ’    std::lock_guard<std::mutex> queue_lock(queue_mutex_);
193вҶ’    std::queue<IncomingRequest> empty;
