 26вҶ’class DdsTopicDiscovery::PublisherListener
 27вҶ’    : public dds::sub::NoOpDataReaderListener<dds::topic::PublicationBuiltinTopicData> {
 28вҶ’ public:
 29вҶ’  PublisherListener(DdsTopicDiscovery& discovery, int32_t domain_id) : discovery_(discovery), domain_id_(domain_id) {}
 30вҶ’
 31вҶ’  void on_data_available(dds::sub::DataReader<dds::topic::PublicationBuiltinTopicData>& reader) override {
 32вҶ’    try {
 33вҶ’      auto samples = reader.select().state(dds::sub::status::DataState::new_instance()).take();
 34вҶ’
 35вҶ’      for (const auto& sample : samples) {
 36вҶ’        if (!sample.info().valid()) {
 37вҶ’          continue;
 38вҶ’        }
 39вҶ’
 40вҶ’        const auto& topic_name = sample.data().topic_name();
