114вҶ’
115вҶ’    dds::topic::Topic<dds::core::xtypes::DynamicData> topic(participant, topic_name, struct_type.name());
116вҶ’
117вҶ’    dds::sub::Subscriber subscriber(participant);
118вҶ’    dds::sub::DataReader<dds::core::xtypes::DynamicData> reader(subscriber, topic);
119вҶ’
120вҶ’    auto listener = std::make_shared<InternalReaderListener>(topic_name, *this);
121вҶ’    reader.set_listener(listener);
122вҶ’
123вҶ’    subscriptions_.emplace(
124вҶ’        std::piecewise_construct, std::forward_as_tuple(topic_name),
