 public:
  using DdsMessageCallback = std::function<void(
      const std::string& topic_name,
      std::shared_ptr<std::vector<std::byte>> cdr_data,
      uint64_t timestamp_ns)>;

  explicit FastDdsSubscriptionManager(FastDdsTopicDiscovery& discovery);
  ~FastDdsSubscriptionManager();

  FastDdsSubscriptionManager(const FastDdsSubscriptionManager&) = delete;
  FastDdsSubscriptionManager& operator=(const FastDdsSubscriptionManager&) = delete;

  void set_message_callback(DdsMessageCallback callback);
  bool subscribe(const std::string& topic_name);
  bool unsubscribe(const std::string& topic_name);
  size_t ref_count(const std::string& topic_name) const;
  void unsubscribe_all();

 private:
  class InternalReaderListener;  // DataReaderListener subclass

  struct SubscriptionInfo {
    eprosima::fastdds::dds::Subscriber* subscriber;
    eprosima::fastdds::dds::Topic* topic;
    eprosima::fastdds::dds::DataReader* reader;
    std::unique_ptr<InternalReaderListener> listener;
    size_t reference_count;
  };

  FastDdsTopicDiscovery& discovery_;
  DdsMessageCallback callback_;
  mutable std::mutex mutex_;
  std::unordered_map<std::string, SubscriptionInfo> subscriptions_;
};

}  // namespace pj_bridge
```

#### `fastdds/src/fastdds_subscription_manager.cpp`

The `InternalReaderListener` class overrides `on_data_available()`. The critical question is how to get raw CDR bytes.

**RTI to FastDDS API mapping for subscription/CDR extraction:**

| Operation | RTI Connext DDS | FastDDS 3.4 |
|-----------|----------------|-------------|
| Register type | `rti::domain::register_type(participant, name, struct_type, ser_prop)` | `TypeSupport ts(new DynamicPubSubType(dynamic_type)); ts.register_type(participant)` |
| Create subscriber | `dds::sub::Subscriber(participant)` | `participant->create_subscriber(SUBSCRIBER_QOS_DEFAULT)` |
| Create topic | `dds::topic::Topic<DynamicData>(participant, name, type_name)` | `participant->create_topic(name, type_name, TOPIC_QOS_DEFAULT)` |
| Create reader | `dds::sub::DataReader<DynamicData>(subscriber, topic)` | `subscriber->create_datareader(topic, DATAREADER_QOS_DEFAULT, listener)` |
| Set listener | `reader.set_listener(listener)` | Set at creation or `reader->set_listener(listener, mask)` |
| Skip deserialization | `DynamicDataTypeSerializationProperty::skip_deserialization(true)` | **No equivalent** -- see strategy below |
| Take samples | `reader.take()` | `reader->take_next_sample(&dyn_data, &info)` |
| Get CDR buffer | `sample.data().get_cdr_buffer()` returns `(ptr, size)` | **Must serialize DynamicData** via `DynamicPubSubType::serialize()` -- see strategy below |
| Get timestamp | `sample.info().source_timestamp()` (sec + nanosec) | `info.source_timestamp.seconds()` + `info.source_timestamp.nanosec()` |
| Destroy reader | `reader.close()` | `subscriber->delete_datareader(reader)` |
| Destroy subscriber | `subscriber.close()` | `participant->delete_subscriber(subscriber)` |
| Destroy topic | N/A (implicit) | `participant->delete_topic(topic)` |

**CDR extraction strategy (critical design decision):**

RTI has `get_cdr_buffer()` which returns raw CDR directly from the DynamicData, and `skip_deserialization(true)` to avoid deserializing in the first place. FastDDS 3.4 does not have a direct equivalent.

There are two approaches:

**Approach A: DynamicPubSubType serialize (simpler, more portable)**
```cpp
void on_data_available(DataReader* reader) override {
  DynamicData::_ref_type dyn_data = DynamicDataFactory::get_instance()->create_data(dynamic_type_);
  SampleInfo info;
  while (reader->take_next_sample(&dyn_data, &info) == RETCODE_OK) {
    if (info.instance_state != ALIVE_INSTANCE_STATE) continue;

    // Serialize DynamicData back to CDR
    DynamicPubSubType pub_sub_type(dynamic_type_);
    SerializedPayload_t payload;
    payload.reserve(pub_sub_type.getSerializedSizeProvider(&dyn_data)());
    pub_sub_type.serialize(&dyn_data, &payload);

    // payload.data points to CDR bytes, payload.length is the size
    auto cdr = std::make_shared<std::vector<std::byte>>(payload.length);
    std::memcpy(cdr->data(), payload.data, payload.length);

    uint64_t ts_ns = (uint64_t(info.source_timestamp.seconds()) * 1'000'000'000ULL)
                   + info.source_timestamp.nanosec();
    callback_(topic_name_, std::move(cdr), ts_ns);
  }
}
```

This approach deserializes and then re-serializes, which is suboptimal but correct. The `DynamicPubSubType` can be cached per subscription to avoid repeated construction.

**Approach B: RTPS-layer raw payload interception (advanced, better performance)**

FastDDS allows creating custom `TopicDataType` implementations. By subclassing `TopicDataType` (or `DynamicPubSubType`) and overriding `deserialize()`, you could capture the raw `SerializedPayload_t` before deserialization. This would require:

```cpp
class RawCapturePubSubType : public DynamicPubSubType {
 public:
  bool deserialize(SerializedPayload_t& payload, void* data) override {
    // Capture raw CDR before deserialization
    captured_payload_ = std::make_shared<std::vector<std::byte>>(payload.length);
    std::memcpy(captured_payload_->data(), payload.data, payload.length);
    // Still deserialize so SampleInfo is valid
    return DynamicPubSubType::deserialize(payload, data);
  }
  std::shared_ptr<std::vector<std::byte>> captured_payload_;
};
```

**Recommendation**: Start with Approach A for correctness. Benchmark it. If the serialize/deserialize round-trip becomes a bottleneck (unlikely for PlotJuggler rates of ~50 Hz aggregation), switch to Approach B. Note: the RTI backend also does a memcpy for `get_cdr_buffer()`, so the overhead difference is primarily the re-serialization step.

#### `fastdds/include/pj_bridge_fastdds/fastdds_topic_source.hpp` and `.cpp`

Thin adapter. Identical pattern to `RtiTopicSource`:

